<script>
function autocomplete(inputElement, autoCompSrchAra, autoCompSrchJsonAra) {
  /*the autocomplete function takes two arguments,
  the text field element and an array of possible autocompleted values:*/
  var currentFocus;
  /*execute a function when someone writes in the text field:*/
  inputElement.addEventListener("input", function(e) {
      var dynDivOtr, dynDivInr, idx, val = this.value;
      /*close any already open lists of autocompleted values*/
      closeAllLists();
      if (!val) { return false;}
      currentFocus = -1;
      /*create a DIV element that will contain the items (values):*/
      dynDivOtr = document.createElement("DIV");
      dynDivOtr.setAttribute("id", this.id + "autocomplete-list");
      dynDivOtr.setAttribute("class", "autocomplete-items");
      /*append the DIV element as a child of the autocomplete container:*/
      this.parentNode.appendChild(dynDivOtr);
      /*for each item in the array...*/
      for (idx = 0; idx < autoCompSrchAra.length; idx++) {
        /*check if the item starts with the same letters as the text field value:
        if (autoCompSrchAra[idx].substr(0, val.length).toUpperCase() == val.toUpperCase()) {*/
        /*check if the item contains with the same letters as the text field value:*/
        if ((autoCompSrchAra[idx].toUpperCase()).includes(val.toUpperCase()))  {
          /*create a DIV element for each matching element:*/
          dynDivInr = document.createElement("DIV");
/*  make the matching letters bold:
          dynDivInr.innerHTML = "<strong>" + autoCompSrchAra[idx].substr(0, val.length) + "</strong>";
          dynDivInr.innerHTML += autoCompSrchAra[idx].substr(val.length);
*/
          /*make the matching letters bold:*/
          valUpr=val.toUpperCase();
          nvProduct = autoCompSrchAra[idx].toUpperCase();
          dynDivInr.innerHTML = autoCompSrchAra[idx].substr(0,nvProduct.indexOf(valUpr));
          dynDivInr.innerHTML += "<strong>" + autoCompSrchAra[idx].substr(nvProduct.indexOf(valUpr), valUpr.length) + "</strong>";
          dynDivInr.innerHTML += autoCompSrchAra[idx].substr(nvProduct.indexOf(valUpr)+valUpr.length);
          /*insert a input field that will hold the current array item's value:*/
          dynDivInr.innerHTML += "<input type='hidden' value='" + autoCompSrchAra[idx] + "' data-json='" + autoCompSrchJsonAra[idx] + "'>";
          /*execute a function when someone clicks on the item value (DIV element):*/
          dynDivInr.addEventListener("click", function(e) {
              /*insert the value for the autocomplete text field:*/
              inputElement.value = this.getElementsByTagName("input")[0].value;
              /*close the list of autocompleted values,
              (or any other open lists of autocompleted values:*/
              closeAllLists();
              driverSettings = JSON.parse(this.getElementsByTagName("input")[0].dataset.json);
              driverService.createManualDropdowns(driverSettings,extraData);
          });
          dynDivOtr.appendChild(dynDivInr);
        }
      }
  });
  /*execute a function presses a key on the keyboard:*/
  inputElement.addEventListener("keydown", function(e) {
      var x = document.getElementById(this.id + "autocomplete-list");
      if (x) x = x.getElementsByTagName("div");
      if (e.keyCode == 40) {
        /*If the arrow DOWN key is pressed,
        increase the currentFocus variable:*/
        currentFocus++;
        /*and and make the current item more visible:*/
        addActive(x);
      } else if (e.keyCode == 38) { //up
        /*If the arrow UP key is pressed,
        decrease the currentFocus variable:*/
        currentFocus--;
        /*and and make the current item more visible:*/
        addActive(x);
      } else if (e.keyCode == 13) {
        /*If the ENTER key is pressed, prevent the form from being submitted,*/
        e.preventDefault();
        if (currentFocus > -1) {
          /*and simulate a click on the "active" item:*/
          if (x) x[currentFocus].click();
        }
      }
  });
  function addActive(x) {
    /*a function to classify an item as "active":*/
    if (!x) return false;
    /*start by removing the "active" class on all items:*/
    removeActive(x);
    if (currentFocus >= x.length) currentFocus = 0;
    if (currentFocus < 0) currentFocus = (x.length - 1);
    /*add class "autocomplete-active":*/
    x[currentFocus].classList.add("autocomplete-active");
  }
  function removeActive(x) {
    /*a function to remove the "active" class from all autocomplete items:*/
    for (var idx = 0; idx < x.length; idx++) {
      x[idx].classList.remove("autocomplete-active");
    }
  }
  function closeAllLists(elmnt) {
    /*close all autocomplete lists in the document,
    except the one passed as an argument:*/
    var x = document.getElementsByClassName("autocomplete-items");
    for (var idx = 0; idx < x.length; idx++) {
      if (elmnt != x[idx] && elmnt != inputElement) {
        x[idx].parentNode.removeChild(x[idx]);
      }
    }
  }
  /*execute a function when someone clicks in the document:*/
  document.addEventListener("click", function (e) {
      closeAllLists(e.target);
  });
}

